-- Imposta encoding UTF-8
SET NAMES 'utf8mb4';
SET CHARACTER SET utf8mb4;

-- ------------------------------------------------------------
-- 1. TABELLE DI LOOKUP
-- ------------------------------------------------------------

CREATE TABLE IF NOT EXISTS categorie_grammaticali (
    cat         VARCHAR(8)   NOT NULL,
    descrizione VARCHAR(60)  NOT NULL,
    PRIMARY KEY (cat)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


CREATE TABLE IF NOT EXISTS tipi_voce (
    tipo        VARCHAR(20)  NOT NULL,
    descrizione VARCHAR(80)  NOT NULL,
    PRIMARY KEY (tipo)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


-- ------------------------------------------------------------
-- 2. TABELLA PRINCIPALE: voci_dizionario
-- ------------------------------------------------------------

CREATE TABLE IF NOT EXISTS voci_dizionario (
    id          INT UNSIGNED     NOT NULL AUTO_INCREMENT,
    num         SMALLINT UNSIGNED NOT NULL  COMMENT 'Numero progressivo nel file sorgente',
    tipo        VARCHAR(20)       NOT NULL  COMMENT 'lemma | locuzione | lemma_variant',
    voce        VARCHAR(120)      NOT NULL  COMMENT 'Termine dialettale',
    cat         VARCHAR(8)        NOT NULL  COMMENT 'Categoria grammaticale',
    italiano    TEXT              NOT NULL  COMMENT 'Traduzione/equivalente italiano',
    et_audio    VARCHAR(120)      NOT NULL  COMMENT 'Etichetta file audio (senza estensione)',
    sorgente    VARCHAR(20)       NOT NULL  COMMENT 'File di origine: AA_01032026 | BB_01032026',
    PRIMARY KEY (id),
    INDEX idx_voce      (voce),
    INDEX idx_cat       (cat),
    INDEX idx_tipo      (tipo),
    INDEX idx_sorgente  (sorgente),
    INDEX idx_num_sorg  (num, sorgente),
    CONSTRAINT fk_cat  FOREIGN KEY (cat)  REFERENCES categorie_grammaticali(cat),
    CONSTRAINT fk_tipo FOREIGN KEY (tipo) REFERENCES tipi_voce(tipo)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci
  COMMENT='Dizionario dialettale - voci AA e BB';

